    56→const ingestSessionHandler = os.ingestSession
    57→	.use(authMiddleware)
    58→	.handler(async ({ input, context }) => {
    59→		const orgId =
    60→			input.organizationId ??
    61→			((context.session as Record<string, unknown>).activeOrganizationId as
    62→				| string
    63→				| null) ??
    64→			context.user.id;
    65→
    66→		if (input.organizationId) {
    67→			const membership = await db
    68→				.select({ id: member.id })
    69→				.from(member)
    70→				.where(
    71→					and(
    72→						eq(member.organizationId, input.organizationId),
    73→						eq(member.userId, context.user.id),
    74→					),
    75→				)
    76→				.limit(1);
    77→
    78→			if (membership.length === 0) {
    79→				throw new ORPCError("FORBIDDEN", {
    80→					message: "Not a member of the specified organization",
    81→				});
    82→			}
    83→		}
    84→
    85→		const adapter = getAdapter(input.source);
    86→		await adapter.ingest(getClickhouse(), input, {
    87→			userId: context.user.id,
    88→			organizationId: orgId,
    89→		});
    90→
    91→		return {
    92→			success: true as const,
    93→			sessionId: input.sessionId,
    94→		};
    95→	});
    96→
    97→const getOrganizationSessionCount = os.getOrganizationSessionCount
    98→	.use(authMiddleware)
    99→	.handler(async ({ input, context }) => {
   100→		const membership = await db
   101→			.select({ id: member.id })
   102→			.from(member)
   103→			.where(
   104→				and(
   105→					eq(member.organizationId, input.organizationId),
   106→					eq(member.userId, context.user.id),
   107→				),
   108→			)
   109→			.limit(1);
   110→
   111→		if (membership.length === 0) {
   112→			throw new ORPCError("FORBIDDEN", {
   113→				message: "Not a member of this organization",
   114→			});
   115→		}
   116→
   117→		const count = await getOrgSessionCount(input.organizationId);
   118→		return { count };
   119→	});
   120→
   121→const deleteOrganization = os.deleteOrganization
   122→	.use(authMiddleware)
   123→	.handler(async ({ input, context }) => {
   124→		const orgId = input.organizationId;
   125→		const userId = context.user.id;
   126→		console.log(`[deleteOrganization] user=${userId} org=${orgId}`);
   127→
   128→		// Check user has more than one org
   129→		const memberships = await db
   130→			.select({ organizationId: member.organizationId })
   131→			.from(member)
   132→			.where(eq(member.userId, userId));
   133→
   134→		if (memberships.length <= 1) {
   135→			console.log(
   136→				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
   137→			);
   138→			throw new ORPCError("BAD_REQUEST", {
   139→				message: "Cannot delete your only organization",
   140→			});
   141→		}
   142→
   143→		// Verify user is owner of the target org
   144→		const ownership = await db
   145→			.select({ id: member.id })
   146→			.from(member)
   147→			.where(
   148→				and(
   149→					eq(member.organizationId, orgId),
   150→					eq(member.userId, userId),
   151→					eq(member.role, "owner"),
   152→				),
   153→			)
   154→			.limit(1);
   155→
   156→		if (ownership.length === 0) {
   157→			console.log(
   158→				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
   159→			);
   160→			throw new ORPCError("FORBIDDEN", {
   161→				message: "Only the organization owner can delete it",
   162→			});
   163→		}
   164→
   165→		try {
   166→			// Fire-and-forget: ClickHouse mutations are slow, don't block on them
   167→			deleteOrgSessions(orgId);
   168→
   169→			// Delete the organization from Postgres (cascade handles member + invitation)
   170→			console.log(`[deleteOrganization] deleting org=${orgId} from Postgres`);
   171→			await db.delete(organization).where(eq(organization.id, orgId));
   172→
   173→			// Clear activeOrganizationId on user sessions that reference the deleted org
   174→			console.log(
   175→				`[deleteOrganization] clearing activeOrganizationId references for org=${orgId}`,
   176→			);
   177→			await db
   178→				.update(session)
   179→				.set({ activeOrganizationId: null })
   180→				.where(eq(session.activeOrganizationId, orgId));
   181→
   182→			console.log(`[deleteOrganization] success for org=${orgId}`);
   183→			return { success: true as const };
   184→		} catch (error) {
   185→			if (error instanceof ORPCError) throw error;
   186→			console.error(`[deleteOrganization] failed for org=${orgId}:`, error);
   187→			throw error;
   188→		}
   189→	});
   190→
   191→export const router = os.router({
