    23→/**
    24→ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
    25→ */
    26→export async function getOverviewKPIs(
    27→	orgId: string,
    28→	startDate: string,
    29→	endDate: string,
    30→): Promise<OverviewKPIs> {
    31→	const org = escapeString(orgId);
    32→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
    33→
    34→	const query = `
    35→    SELECT
    36→      uniq(user_id) as distinct_users,
    37→      count() as distinct_sessions,
    38→      uniq(if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))) as distinct_projects,
    39→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN subagent_types as val WHERE ${buildAbsoluteDateFilter(startDate, endDate)} AND organization_id = '${org}' AND val != '') as distinct_subagents,
    40→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN skills as val WHERE ${buildAbsoluteDateFilter(startDate, endDate)} AND organization_id = '${org}' AND val != '') as distinct_skills,
    41→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN slash_commands as val WHERE ${buildAbsoluteDateFilter(startDate, endDate)} AND organization_id = '${org}' AND val != '') as distinct_slash_commands,
    42→      (SELECT count() FROM rudel.session_analytics WHERE organization_id = '${org}') as total_sessions
    43→    FROM rudel.session_analytics
    44→    WHERE ${dateFilter}
    45→      AND organization_id = '${org}'
    46→  `;
    47→
    48→	const result = await queryClickhouse<OverviewKPIs>(query);
    49→	const row = result[0];
    50→	if (!row) {
    51→		return {
    52→			distinct_users: 0,
    53→			distinct_sessions: 0,
    54→			distinct_projects: 0,
    55→			distinct_subagents: 0,
    56→			distinct_skills: 0,
    57→			distinct_slash_commands: 0,
    58→			total_sessions: 0,
    59→		};
    60→	}
    61→	// ClickHouse returns UInt64 as strings when output_format_json_quote_64bit_integers is true (the default)
    62→	return {
    63→		distinct_users: Number(row.distinct_users),
    64→		distinct_sessions: Number(row.distinct_sessions),
    65→		distinct_projects: Number(row.distinct_projects),
    66→		distinct_subagents: Number(row.distinct_subagents),
    67→		distinct_skills: Number(row.distinct_skills),
    68→		distinct_slash_commands: Number(row.distinct_slash_commands),
    69→		total_sessions: Number(row.total_sessions),
    70→	};
    71→}
