    73→/**
    74→ * Get token usage broken down by model and day
    75→ */
    76→export async function getModelTokensTrend(
    77→	orgId: string,
    78→	startDate: string,
    79→	endDate: string,
    80→): Promise<ModelTokensTrendData[]> {
    81→	const org = escapeString(orgId);
    82→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
    83→
    84→	const query = `
    85→    SELECT
    86→      toDate(session_date) as date,
    87→      model_used as model,
    88→      sum(total_tokens) as total_tokens,
    89→      sum(input_tokens) as input_tokens,
    90→      sum(output_tokens) as output_tokens
    91→    FROM rudel.session_analytics
    92→    WHERE ${dateFilter}
    93→      AND organization_id = '${org}'
    94→      AND model_used != ''
    95→      AND model_used != 'unknown'
    96→    GROUP BY date, model
    97→    ORDER BY date ASC, total_tokens DESC
    98→  `;
    99→
   100→	return queryClickhouse<ModelTokensTrendData>(query);
   101→}
