   131→/**
   132→ * Generate rule-based insights from current data
   133→ */
   134→export async function getOverviewInsights(
   135→	orgId: string,
   136→	startDate: string,
   137→	endDate: string,
   138→): Promise<Insight[]> {
   139→	const org = escapeString(orgId);
   140→	const insights: Insight[] = [];
   141→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
   142→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
   143→	const prevStart = new Date(prevEnd.getTime() - periodMs);
   144→	const prevStartStr = prevStart.toISOString().slice(0, 10);
   145→	const prevEndStr = prevEnd.toISOString().slice(0, 10);
   146→
   147→	const currentPeriodQuery = `
   148→    SELECT
   149→      count() as total_sessions,
   150→      uniq(user_id) as total_users,
   151→      round(avg(actual_duration_min), 2) as avg_duration_min
   152→    FROM rudel.session_analytics
   153→    WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
   154→      AND organization_id = '${org}'
   155→  `;
   156→
   157→	const previousPeriodQuery = `
   158→    SELECT
   159→      count() as total_sessions,
   160→      uniq(user_id) as total_users,
   161→      round(avg(actual_duration_min), 2) as avg_duration_min
   162→    FROM rudel.session_analytics
   163→    WHERE ${buildAbsoluteDateFilter(prevStartStr, prevEndStr)}
   164→      AND organization_id = '${org}'
   165→  `;
   166→
   167→	interface PeriodStats {
   168→		total_sessions: number;
   169→		total_users: number;
   170→		avg_duration_min: number;
   171→	}
   172→
   173→	const [currentData, previousData] = await Promise.all([
   174→		queryClickhouse<PeriodStats>(currentPeriodQuery),
   175→		queryClickhouse<PeriodStats>(previousPeriodQuery),
   176→	]);
   177→
   178→	const current = currentData[0];
   179→	const previous = previousData[0] || { total_sessions: 0 };
   180→
   181→	// Insight 1: Session trend analysis
   182→	if (current && previous) {
   183→		const sessionChange =
   184→			previous.total_sessions > 0
   185→				? ((current.total_sessions - previous.total_sessions) /
   186→						previous.total_sessions) *
   187→					100
   188→				: 0;
   189→
   190→		if (Math.abs(sessionChange) >= 10) {
   191→			const direction = sessionChange > 0 ? "up" : "down";
   192→			const severity = sessionChange > 0 ? "positive" : "warning";
   193→			insights.push({
   194→				type: "trend",
   195→				severity,
   196→				message: `Team activity ${direction} ${Math.abs(sessionChange).toFixed(1)}% this week`,
   197→				link: "/dashboard/team",
   198→			});
   199→		}
   200→	}
   201→
   202→	// Insight 2: Top performer identification
   203→	const topPerformerQuery = `
   204→    SELECT
   205→      user_id,
   206→      count() as sessions,
   207→      round(sum(actual_duration_min) / 60, 1) as total_hours
   208→    FROM rudel.session_analytics
   209→    WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
   210→      AND organization_id = '${org}'
   211→    GROUP BY user_id
   212→    ORDER BY sessions DESC
   213→    LIMIT 1
   214→  `;
   215→
   216→	const topPerformer = await queryClickhouse<{
   217→		user_id: string;
   218→		sessions: number;
   219→		total_hours: number;
   220→	}>(topPerformerQuery);
   221→	if (topPerformer.length > 0 && topPerformer[0]) {
   222→		const performer = topPerformer[0];
   223→		const [userData] = await db
   224→			.select({ name: user.name })
   225→			.from(user)
   226→			.where(eq(user.id, performer.user_id))
   227→			.limit(1);
   228→		const displayName =
   229→			userData?.name || `${performer.user_id.substring(0, 8)}...`;
   230→
   231→		insights.push({
   232→			type: "performer",
   233→			severity: "info",
   234→			message: `Top contributor: ${displayName} (${performer.sessions} sessions, ${performer.total_hours}h)`,
   235→			link: `/dashboard/developers/${performer.user_id}`,
   236→		});
   237→	}
   238→
   239→	// Insight 3: Knowledge silos detection (uses a wider 30-day window)
   240→	const knowledgeSilosQuery = `
   241→    SELECT
   242→      project_path,
   243→      uniq(user_id) as unique_users,
   244→      count() as sessions
   245→    FROM rudel.session_analytics
   246→    WHERE ${buildDateFilter(30)}
   247→      AND organization_id = '${org}'
   248→    GROUP BY project_path
   249→    HAVING unique_users = 1 AND sessions >= 5
   250→    ORDER BY sessions DESC
   251→  `;
   252→
   253→	const silos = await queryClickhouse<{
   254→		project_path: string;
   255→		unique_users: number;
   256→		sessions: number;
   257→	}>(knowledgeSilosQuery);
   258→	if (silos.length > 0) {
   259→		insights.push({
   260→			type: "alert",
   261→			severity: "warning",
   262→			message: `${silos.length} project${silos.length > 1 ? "s" : ""} with only one developer - risk of knowledge silos`,
   263→			link: "/dashboard/projects",
   264→		});
   265→	}
   266→
   267→	return insights.slice(0, 3);
   268→}
