   277→/**
   278→ * Get team summary with previous period comparison
   279→ */
   280→export async function getTeamSummaryWithComparison(
   281→	orgId: string,
   282→	startDate: string,
   283→	endDate: string,
   284→) {
   285→	const org = escapeString(orgId);
   286→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
   287→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
   288→	const prevStart = new Date(prevEnd.getTime() - periodMs);
   289→	const prevStartStr = prevStart.toISOString().slice(0, 10);
   290→	const prevEndStr = prevEnd.toISOString().slice(0, 10);
   291→
   292→	const currentQuery = `
   293→    SELECT
   294→      count() as total_sessions,
   295→      uniq(user_id) as active_users,
   296→      round(avg(actual_duration_min), 2) as avg_duration_min,
   297→      round(count() / uniq(user_id), 2) as avg_sessions_per_user
   298→    FROM rudel.session_analytics
   299→    WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
   300→      AND organization_id = '${org}'
   301→  `;
   302→
   303→	const previousQuery = `
   304→    SELECT
   305→      count() as total_sessions,
   306→      uniq(user_id) as active_users,
   307→      round(avg(actual_duration_min), 2) as avg_duration_min,
   308→      round(count() / uniq(user_id), 2) as avg_sessions_per_user
   309→    FROM rudel.session_analytics
   310→    WHERE ${buildAbsoluteDateFilter(prevStartStr, prevEndStr)}
   311→      AND organization_id = '${org}'
   312→  `;
   313→
   314→	const [currentData, previousData] = await Promise.all([
   315→		queryClickhouse<TeamSummaryPeriodData>(currentQuery),
   316→		queryClickhouse<TeamSummaryPeriodData>(previousQuery),
   317→	]);
   318→
   319→	const defaultPeriod: TeamSummaryPeriodData = {
   320→		total_sessions: 0,
   321→		active_users: 0,
   322→		avg_duration_min: 0,
   323→		avg_sessions_per_user: 0,
   324→	};
   325→
   326→	const current = currentData[0] || defaultPeriod;
   327→	const previous = previousData[0] || defaultPeriod;
   328→
   329→	const calculateChange = (curr: number, prev: number) => {
   330→		if (!prev || prev === 0) return 0;
   331→		return ((curr - prev) / prev) * 100;
   332→	};
   333→
   334→	const changes = {
   335→		total_sessions: calculateChange(
   336→			current.total_sessions || 0,
   337→			previous.total_sessions || 0,
   338→		),
   339→		active_users: calculateChange(
   340→			current.active_users || 0,
   341→			previous.active_users || 0,
   342→		),
   343→		avg_duration_min: calculateChange(
   344→			current.avg_duration_min || 0,
   345→			previous.avg_duration_min || 0,
   346→		),
   347→		avg_sessions_per_user: calculateChange(
   348→			current.avg_sessions_per_user || 0,
   349→			previous.avg_sessions_per_user || 0,
   350→		),
   351→	};
   352→
   353→	return { current, previous, changes };
   354→}
