   356→/**
   357→ * Get session success rate metrics with comparison
   358→ */
   359→export async function getSuccessRateMetrics(
   360→	orgId: string,
   361→	startDate: string,
   362→	endDate: string,
   363→) {
   364→	const org = escapeString(orgId);
   365→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
   366→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
   367→	const prevStart = new Date(prevEnd.getTime() - periodMs);
   368→	const prevStartStr = prevStart.toISOString().slice(0, 10);
