	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);

	const [mainResult, subagentsResult, skillsResult, slashResult, totalResult] =
		await Promise.all([
			queryClickhouse<{
				distinct_users: number;
				distinct_sessions: number;
				distinct_projects: number;
			}>(`
