    19→interface TaskClassificationChartProps {
    20→	data: TaskClassification[];
    21→	onTaskTypeClick?: (taskType: string) => void;
    22→}
    23→
    24→const COLORS: Record<string, string> = {
    25→	bug_fix: "#ef4444",
    26→	new_feature: "#3b82f6",
    27→	refactoring: "#8b5cf6",
    28→	tests: "#10b981",
    29→	documentation: "#f59e0b",
    30→	research: "#6366f1",
    31→	unknown: "#6b7280",
    32→};
    33→
    34→const LABELS: Record<string, string> = {
    35→	bug_fix: "Bug Fix",
    36→	new_feature: "New Feature",
    37→	refactoring: "Refactoring",
    38→	tests: "Tests",
    39→	documentation: "Documentation",
    40→	research: "Research",
    41→	unknown: "Unknown",
    42→};
    43→
    44→export function TaskClassificationChart({
    45→	data,
    46→	onTaskTypeClick,
    47→}: TaskClassificationChartProps) {
    48→	const chartData = data.map((item) => ({
    49→		name: LABELS[item.task_type] || item.task_type,
    50→		value: item.count,
    51→		percentage: item.percentage,
    52→		confidence: item.avg_confidence,
    53→		task_type: item.task_type,
    54→	}));
    55→
    56→	const renderCustomLabel = (props: PieLabelRenderProps) => {
    57→		const cx = Number(props.cx) || 0;
    58→		const cy = Number(props.cy) || 0;
    59→		const midAngle = Number(props.midAngle) || 0;
    60→		const innerRadius = Number(props.innerRadius) || 0;
    61→		const outerRadius = Number(props.outerRadius) || 0;
    62→		const percentage =
    63→			Number((props as unknown as Record<string, unknown>).percentage) || 0;
    64→
    65→		const RADIAN = Math.PI / 180;
    66→		const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
    67→		const x = cx + radius * Math.cos(-midAngle * RADIAN);
    68→		const y = cy + radius * Math.sin(-midAngle * RADIAN);
    69→
    70→		if (percentage < 5) return null;
    71→
    72→		return (
    73→			<text
    74→				x={x}
    75→				y={y}
    76→				fill="white"
    77→				textAnchor={x > cx ? "start" : "end"}
    78→				dominantBaseline="central"
    79→				className="text-sm font-semibold"
    80→			>
    81→				{`${percentage.toFixed(1)}%`}
    82→			</text>
    83→		);
    84→	};
    85→
    86→	const CustomTooltip = ({ active, payload }: Record<string, unknown>) => {
    87→		if (active && payload && Array.isArray(payload) && payload.length) {
    88→			const d = (payload[0] as Record<string, unknown>).payload as Record<
    89→				string,
    90→				unknown
    91→			>;
    92→			return (
    93→				<div className="bg-input p-3 border border-border rounded-lg shadow-lg">
    94→					<p className="font-semibold text-foreground">{d.name as string}</p>
    95→					<p className="text-sm text-muted">
    96→						Sessions:{" "}
    97→						<span className="font-semibold text-foreground">
    98→							{d.value as number}
    99→						</span>
   100→					</p>
   101→					<p className="text-sm text-muted">
   102→						Percentage:{" "}
   103→						<span className="font-semibold text-foreground">
   104→							{(d.percentage as number).toFixed(1)}%
   105→						</span>
   106→					</p>
   107→					<p className="text-sm text-muted">
   108→						Avg Confidence:{" "}
   109→						<span className="font-semibold text-foreground">
   110→							{((d.confidence as number) * 100).toFixed(0)}%
   111→						</span>
   112→					</p>
   113→				</div>
   114→			);
   115→		}
   116→		return null;
   117→	};
   118→
   119→	return (
   120→		<div className="w-full h-[400px]">
   121→			<ResponsiveContainer width="100%" height="100%">
   122→				<PieChart>
   123→					<Pie
   124→						data={chartData}
   125→						cx="50%"
   126→						cy="50%"
   127→						labelLine={false}
   128→						label={renderCustomLabel}
   129→						outerRadius={120}
   130→						fill="#8884d8"
   131→						dataKey="value"
   132→						onClick={(d) => {
   133→							if (onTaskTypeClick) {
   134→								onTaskTypeClick(d.task_type);
   135→							}
   136→						}}
   137→						cursor="pointer"
   138→					>
   139→						{chartData.map((entry, index) => (
   140→							<Cell
   141→								// biome-ignore lint/suspicious/noArrayIndexKey: static pie chart segments
   142→								key={`cell-${index}`}
   143→								fill={COLORS[entry.task_type] || COLORS.unknown}
   144→								className="hover:opacity-80 transition-opacity"
   145→							/>
   146→						))}
   147→					</Pie>
   148→					<Tooltip content={<CustomTooltip />} />
   149→					<Legend
   150→						verticalAlign="bottom"
   151→						height={36}
   152→						formatter={(value) => {
   153→							const match = chartData.find((item) => item.name === value);
   154→							return `${value} (${match?.value || 0})`;
   155→						}}
   156→					/>
   157→				</PieChart>
   158→			</ResponsiveContainer>
   159→		</div>
   160→	);
   161→}
