   138→					.reduce(
   139→						(sum, d) =>
   140→							sum +
   141→							((d[
   142→								currentMetric.key as keyof DeveloperTrendDataPoint
   143→							] as number) ?? 0),
   144→						0,
   145→					);
   146→			}
