   148→			return dateObj;
   149→		});
   150→
   151→		return { chartData, seriesList };
   152→	}, [
   153→		data,
   154→		topDevelopers,
   155→		topDevelopersSet,
   156→		hasOther,
   157→		selectedMetric,
