   270→						<Tooltip
   271→							contentStyle={{
   272→								backgroundColor: tooltipBg,
   273→								border: `1px solid ${tooltipBorder}`,
   274→								borderRadius: "8px",
   275→								padding: "12px",
   276→							}}
   277→							formatter={(value, name) => {
   278→								if (!name || name === "date" || name === "displayDate")
