    50→	const labelMap: Record<string, string> = {
    51→		session_count: "Session Count",
    52→		avg_duration: "Avg Duration (min)",
    53→		total_duration: "Total Duration (hours)",
    54→		avg_interactions: "Avg Interactions",
    55→		total_interactions: "Total Interactions",
    56→		avg_response_time: "Avg Response Time (sec)",
