   137→				let total = 0;
   138→				for (const key of rawSplitKeys) {
   139→					const displayKey = splitKeyDisplayMap[key];
   140→					const val = item.split_values?.[key] || 0;
   141→					origValues[displayKey] = val;
   142→					total += val;
   143→				}
   144→				row._total = total;
