   222→								>
   223→									{entry.name as string}: {displayValue as string}
   224→									{showPercentage &&
   225→										originalValues &&
   226→										originalValues[entry.name as string] !== undefined && (
   227→											<span className="text-muted ml-1">
   228→												({(entry.value as number).toFixed(1)}%)
   229→											</span>
   230→										)}
   231→								</p>
   232→							);
   233→						},
   234→					)}
   235→				</div>
   236→			);
   237→		}
   238→		return null;
   239→	};
   240→
   241→	return (
   242→		<div className="w-full">
