    34→
    35→function formatCompactNumber(num: number): string {
    36→	if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(1)}B`;
    37→	if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(1)}M`;
    38→	if (num >= 1_000) return `${(num / 1_000).toFixed(1)}K`;
    39→	return num.toFixed(0);
    40→}
    41→
    42→function shortenModelName(model: string): string {
    43→	if (model === "Other") return "Other";
    44→	return model.replace("claude-", "").replace(/-\d{8}$/, "");
    45→}
    46→
    47→interface ModelTokensChartProps {
    48→	data: ModelTokensTrendData[];
    49→}
    50→
    51→export function ModelTokensChart({ data }: ModelTokensChartProps) {
    52→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
    53→
    54→	const { chartData, models } = useMemo(() => {
    55→		if (data.length === 0) return { chartData: [], models: [] };
    56→
    57→		// Compute total tokens per model to determine top 14
    58→		const modelTotals = new Map<string, number>();
    59→		for (const row of data) {
    60→			modelTotals.set(
    61→				row.model,
    62→				(modelTotals.get(row.model) ?? 0) + row.total_tokens,
    63→			);
    64→		}
    65→
    66→		const sortedModels = Array.from(modelTotals.entries()).sort(
    67→			(a, b) => b[1] - a[1],
    68→		);
    69→		const topModels = sortedModels.slice(0, MAX_SERIES).map(([m]) => m);
    70→		const topModelsSet = new Set(topModels);
    71→		const hasOther = sortedModels.length > MAX_SERIES;
    72→		const modelList = hasOther ? [...topModels, "Other"] : topModels;
    73→
    74→		// Build per-date raw data, bucketing overflow into "Other"
    75→		const rawByDate = new Map<string, Record<string, number>>();
    76→		for (const row of data) {
    77→			const entry = rawByDate.get(row.date) ?? {};
    78→			const key = topModelsSet.has(row.model) ? row.model : "Other";
    79→			entry[key] = (entry[key] ?? 0) + row.total_tokens;
    80→			rawByDate.set(row.date, entry);
    81→		}
    82→
    83→		// Build full date range so zero-value days are included
    84→		const allDates = Array.from(new Set(data.map((r) => r.date))).sort();
    85→		const minDate = new Date(allDates[0]);
    86→		const maxDate = new Date(allDates[allDates.length - 1]);
    87→		const dateRange: string[] = [];
    88→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
    89→			dateRange.push(d.toISOString().split("T")[0]);
    90→		}
    91→
    92→		const sorted = dateRange.map((dateKey) => {
    93→			const entry: Record<string, number | string> = {
    94→				date: new Date(dateKey).toLocaleDateString("en-US", {
    95→					month: "short",
    96→					day: "numeric",
    97→				}),
    98→				_sort: dateKey,
    99→			};
   100→			const raw = rawByDate.get(dateKey) ?? {};
   101→			for (const model of modelList) {
   102→				entry[model] = raw[model] ?? 0;
   103→			}
   104→			return entry;
   105→		});
   106→
   107→		return { chartData: sorted, models: modelList };
   108→	}, [data]);
   109→
   110→	if (chartData.length === 0) return null;
   111→
   112→	return (
   113→		<ResponsiveContainer width="100%" height={400}>
   114→			<BarChart
   115→				data={chartData}
   116→				margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
   117→			>
   118→				<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   119→				<XAxis
   120→					dataKey="date"
   121→					tick={{ fontSize: 12 }}
   122→					angle={-45}
   123→					textAnchor="end"
   124→					height={80}
   125→					tickMargin={8}
   126→				/>
   127→				<YAxis tick={{ fontSize: 12 }} tickFormatter={formatCompactNumber} />
   128→				<Tooltip
   129→					contentStyle={{
   130→						backgroundColor: tooltipBg,
   131→						border: `1px solid ${tooltipBorder}`,
   132→						borderRadius: "2px",
   133→						padding: "12px",
   134→					}}
   135→					formatter={(value, name) => [
   136→						formatCompactNumber((value as number) ?? 0),
   137→						shortenModelName(String(name ?? "")),
   138→					]}
   139→					labelFormatter={(label) => label}
   140→				/>
   141→				<Legend formatter={shortenModelName} />
   142→				{models.map((model, i) => (
   143→					<Bar
   144→						key={model}
   145→						dataKey={model}
   146→						stackId="1"
   147→						fill={
   148→							model === "Other"
   149→								? OTHER_COLOR
   150→								: MODEL_COLORS[i % MODEL_COLORS.length]
   151→						}
   152→						name={model}
   153→					/>
   154→				))}
   155→			</BarChart>
   156→		</ResponsiveContainer>
   157→	);
   158→}
