    97→			hasOther: sorted.length > MAX_SERIES,
    98→		};
    99→	}, [data]);
   100→
   101→	const { chartData, seriesList } = useMemo(() => {
   102→		const existingDates = Array.from(new Set(data.map((d) => d.date))).sort();
   103→		const allDates: string[] = [];
   104→		if (existingDates.length > 0) {
   105→			const minDate = new Date(existingDates[0]);
