   115→
   116→		// "Other" only applies to summable metrics, not averages
   117→		const showOther = hasOther && selectedMetric !== "success_rate";
   118→		const seriesList = showOther ? [...topDevelopers, "Other"] : topDevelopers;
   119→
   120→		const chartData = allDates.map((date) => {
   121→			const dateObj: Record<string, string | number> = {
   122→				date,
