   138→					.filter((d) => d.date === date && !topDevelopersSet.has(d.user_id))
   139→					.reduce(
   140→						(sum, d) =>
   141→							sum +
   142→							((d[
   143→								currentMetric.key as keyof DeveloperTrendDataPoint
   144→							] as number) ?? 0),
   145→						0,
   146→					);
   147→			}
   148→
   149→			return dateObj;
   150→		});
   151→
   152→		return { chartData, seriesList };
   153→	}, [
   154→		data,
   155→		topDevelopers,
   156→		topDevelopersSet,
   157→		hasOther,
   158→		selectedMetric,
   159→		currentMetric,
   160→	]);
