   282→							}}
   283→							formatter={(value, name) => {
   284→								if (!name || name === "date" || name === "displayDate")
   285→									return null;
   286→								return [
   287→									currentMetric.formatter((value as number) ?? 0),
   288→									formatUsername(String(name)),
   289→								];
   290→							}}
   291→							labelFormatter={(label) => label}
   292→						/>
   293→						<Legend
   294→							layout="vertical"
   295→							align="right"
   296→							verticalAlign="top"
   297→							width={160}
   298→							content={({ payload }) => (
   299→								<ChartLegend payload={payload} formatter={formatUsername} />
   300→							)}
   301→						/>
   302→						{seriesList.map((userId, index) => (
   303→							<Bar
   304→								key={userId}
   305→								dataKey={userId}
   306→								stackId="1"
   307→								fill={
   308→									userId === "Other"
   309→										? OTHER_COLOR
   310→										: DEVELOPER_COLORS[index % DEVELOPER_COLORS.length]
   311→								}
   312→							/>
   313→						))}
   314→					</BarChart>
   315→				)}
   316→			</ResponsiveContainer>
   317→		</div>
   318→	);
   319→}
