    76→export function ProjectTrendChart({ data }: ProjectTrendChartProps) {
    77→	const { tooltipBg, tooltipBorder, gridStroke, axisStroke } = useChartTheme();
    78→	const [selectedMetric, setSelectedMetric] = useState<MetricType>("sessions");
    79→
    80→	const currentMetric = METRICS[selectedMetric];
    81→
    82→	// Rank projects by total sessions (stable ordering across metric changes)
    83→	const { topProjects, topProjectsSet, hasOther } = useMemo(() => {
    84→		const projectTotals = new Map<string, number>();
    85→		for (const d of data) {
    86→			projectTotals.set(
    87→				d.project_path,
    88→				(projectTotals.get(d.project_path) ?? 0) + d.sessions,
    89→			);
    90→		}
    91→		const sorted = Array.from(projectTotals.entries()).sort(
    92→			(a, b) => b[1] - a[1],
    93→		);
    94→		const top = sorted.slice(0, MAX_SERIES).map(([p]) => p);
    95→		return {
    96→			topProjects: top,
    97→			topProjectsSet: new Set(top),
    98→			hasOther: sorted.length > MAX_SERIES,
    99→		};
   100→	}, [data]);
   101→
   102→	const { chartData, seriesList } = useMemo(() => {
   103→		// Build full date range from all data
   104→		const existingDates = Array.from(new Set(data.map((d) => d.date))).sort();
   105→		const allDates: string[] = [];
   106→		if (existingDates.length > 0) {
