   142→					.filter((d) => d.date === date && !topProjectsSet.has(d.project_path))
   143→					.reduce(
   144→						(sum, d) =>
   145→							sum +
   146→							((d[
   147→								currentMetric.key as keyof ProjectTrendDataPoint
   148→							] as number) ?? 0),
   149→						0,
   150→					);
   151→			}
   152→
   153→			return dateObj;
   154→		});
   155→
   156→		return { chartData, seriesList };
   157→	}, [
   158→		data,
   159→		topProjects,
   160→		topProjectsSet,
   161→		hasOther,
   162→		selectedMetric,
   163→		currentMetric,
   164→	]);
   165→
   166→	const formatProjectName = (projectPath: string) => {
   167→		if (projectPath === "Other") return "Other";
   168→		const parts = projectPath.split("/");
   169→		return parts[parts.length - 1] || projectPath.substring(0, 20);
   170→	};
   171→
   172→	return (
   173→		<div className="space-y-4">
   174→			<div className="flex flex-wrap gap-2">
   175→				{Object.entries(METRICS).map(([key, metric]) => {
   176→					const isSelected = selectedMetric === key;
   177→					const Icon = metric.icon;
   178→					return (
   179→						<button
   180→							type="button"
   181→							key={key}
   182→							onClick={() => setSelectedMetric(key as MetricType)}
   183→							className={`
   184→								flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium
   185→								transition-all duration-200
   186→								${
   187→									isSelected
   188→										? "bg-accent-light text-accent-text border-2 border-accent"
   189→										: "bg-surface text-muted border-2 border-transparent hover:bg-hover"
   190→								}
   191→							`}
   192→						>
   193→							<Icon className="w-4 h-4" />
   194→							<span>{metric.label}</span>
   195→						</button>
   196→					);
   197→				})}
   198→			</div>
