   207→						<XAxis
   208→							dataKey="displayDate"
   209→							stroke={axisStroke}
   210→							style={{ fontSize: "12px" }}
   211→							angle={-45}
   212→							textAnchor="end"
   213→							height={80}
   214→							tickMargin={8}
   215→						/>
   216→						<YAxis
   217→							stroke={axisStroke}
   218→							style={{ fontSize: "12px" }}
   219→							tickFormatter={currentMetric.formatter}
   220→							domain={[0, 100]}
   221→						/>
   222→						<Tooltip
   223→							contentStyle={{
