   236→							}}
   237→							labelFormatter={(label) => label}
   238→						/>
   239→						<Legend
   240→							layout="vertical"
   241→							align="right"
   242→							verticalAlign="top"
   243→							width={160}
   244→							content={({ payload }) => (
