   246→							)}
   247→						/>
   248→						{topProjects.map((projectPath, index) => (
   249→							<Line
   250→								key={projectPath}
   251→								type="monotone"
   252→								dataKey={projectPath}
   253→								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
   254→								strokeWidth={2}
   255→								dot={{ r: 3 }}
   256→								activeDot={{ r: 5 }}
   257→								connectNulls
   258→							/>
   259→						))}
   260→					</LineChart>
   261→				) : (
   262→					<BarChart
   263→						data={chartData}
   264→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   265→					>
   266→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   267→						<XAxis
   268→							dataKey="displayDate"
   269→							stroke={axisStroke}
   270→							style={{ fontSize: "12px" }}
   271→							angle={-45}
   272→							textAnchor="end"
   273→							height={80}
   274→							tickMargin={8}
   275→						/>
   276→						<YAxis
   277→							stroke={axisStroke}
   278→							style={{ fontSize: "12px" }}
   279→							tickFormatter={currentMetric.formatter}
   280→						/>
   281→						<Tooltip
   282→							contentStyle={{
   283→								backgroundColor: tooltipBg,
   284→								border: `1px solid ${tooltipBorder}`,
   285→								borderRadius: "8px",
   286→								padding: "12px",
   287→							}}
   288→							formatter={(value, name) => {
   289→								if (!name || name === "date" || name === "displayDate")
   290→									return null;
   291→								return [
   292→									currentMetric.formatter((value as number) ?? 0),
   293→									formatProjectName(String(name)),
