    36→function formatCompactNumber(num: number): string {
    37→	if (num >= 1_000_000_000) return `${(num / 1_000_000_000).toFixed(1)}B`;
    38→	if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(1)}M`;
    39→	if (num >= 1_000) return `${(num / 1_000).toFixed(1)}K`;
    40→	return num.toFixed(0);
    41→}
    42→
    43→function shortenModelName(model: string): string {
    44→	if (model === "Other") return "Other";
    45→	return model.replace("claude-", "").replace(/-\d{8}$/, "");
    46→}
    47→
    48→interface ModelTokensChartProps {
    49→	data: ModelTokensTrendData[];
    50→}
    51→
    52→export function ModelTokensChart({ data }: ModelTokensChartProps) {
    53→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
    54→
    55→	const { chartData, models } = useMemo(() => {
    56→		if (data.length === 0) return { chartData: [], models: [] };
    57→
    58→		// Compute total tokens per model to determine top 14
    59→		const modelTotals = new Map<string, number>();
    60→		for (const row of data) {
    61→			modelTotals.set(
    62→				row.model,
    63→				(modelTotals.get(row.model) ?? 0) + row.total_tokens,
    64→			);
    65→		}
    66→
    67→		const sortedModels = Array.from(modelTotals.entries()).sort(
    68→			(a, b) => b[1] - a[1],
    69→		);
    70→		const topModels = sortedModels.slice(0, MAX_SERIES).map(([m]) => m);
    71→		const topModelsSet = new Set(topModels);
    72→		const hasOther = sortedModels.length > MAX_SERIES;
    73→		const modelList = hasOther ? [...topModels, "Other"] : topModels;
    74→
    75→		// Build per-date raw data, bucketing overflow into "Other"
    76→		const rawByDate = new Map<string, Record<string, number>>();
    77→		for (const row of data) {
    78→			const entry = rawByDate.get(row.date) ?? {};
    79→			const key = topModelsSet.has(row.model) ? row.model : "Other";
    80→			entry[key] = (entry[key] ?? 0) + row.total_tokens;
    81→			rawByDate.set(row.date, entry);
    82→		}
    83→
    84→		// Build full date range so zero-value days are included
    85→		const allDates = Array.from(new Set(data.map((r) => r.date))).sort();
    86→		const minDate = new Date(allDates[0]);
    87→		const maxDate = new Date(allDates[allDates.length - 1]);
    88→		const dateRange: string[] = [];
    89→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
    90→			dateRange.push(d.toISOString().split("T")[0]);
    91→		}
    92→
    93→		const sorted = dateRange.map((dateKey) => {
    94→			const entry: Record<string, number | string> = {
    95→				date: new Date(dateKey).toLocaleDateString("en-US", {
    96→					month: "short",
    97→					day: "numeric",
    98→				}),
    99→				_sort: dateKey,
   100→			};
   101→			const raw = rawByDate.get(dateKey) ?? {};
   102→			for (const model of modelList) {
   103→				entry[model] = raw[model] ?? 0;
   104→			}
   105→			return entry;
   106→		});
   107→
   108→		return { chartData: sorted, models: modelList };
   109→	}, [data]);
   110→
   111→	if (chartData.length === 0) return null;
   112→
   113→	return (
   114→		<ResponsiveContainer width="100%" height={400}>
   115→			<BarChart
   116→				data={chartData}
   117→				margin={{ top: 5, right: 0, left: 20, bottom: 5 }}
   118→			>
   119→				<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   120→				<XAxis
   121→					dataKey="date"
   122→					tick={{ fontSize: 12 }}
   123→					angle={-45}
   124→					textAnchor="end"
   125→					height={80}
   126→					tickMargin={8}
   127→				/>
   128→				<YAxis tick={{ fontSize: 12 }} tickFormatter={formatCompactNumber} />
   129→				<Tooltip
   130→					contentStyle={{
   131→						backgroundColor: tooltipBg,
   132→						border: `1px solid ${tooltipBorder}`,
   133→						borderRadius: "2px",
   134→						padding: "12px",
   135→					}}
   136→					formatter={(value, name) => [
   137→						formatCompactNumber((value as number) ?? 0),
   138→						shortenModelName(String(name ?? "")),
   139→					]}
   140→					labelFormatter={(label) => label}
   141→				/>
   142→				<Legend
   143→					layout="vertical"
   144→					align="right"
   145→					verticalAlign="top"
   146→					width={160}
   147→					content={({ payload }) => (
   148→						<ChartLegend payload={payload} formatter={shortenModelName} />
   149→					)}
   150→				/>
   151→				{models.map((model, i) => (
   152→					<Bar
   153→						key={model}
   154→						dataKey={model}
   155→						stackId="1"
   156→						fill={
   157→							model === "Other"
   158→								? OTHER_COLOR
   159→								: MODEL_COLORS[i % MODEL_COLORS.length]
   160→						}
   161→						name={model}
   162→					/>
   163→				))}
   164→			</BarChart>
   165→		</ResponsiveContainer>
   166→	);
   167→}
