    33→const COLORS = [
    34→	"#3b82f6",
    35→	"#10b981",
    36→	"#f59e0b",
    37→	"#8b5cf6",
    38→	"#ef4444",
    39→	"#06b6d4",
    40→	"#ec4899",
    41→	"#14b8a6",
    42→	"#f97316",
