    49→
    50→export function LearningsTrendChart({
    51→	data,
    52→	splitBy,
    53→	onSplitByChange,
    54→	userMap,
    55→}: LearningsTrendChartProps) {
    56→	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
    57→	const [isCumulative, setIsCumulative] = useState(true);
    58→
    59→	// All series keys from the data
    60→	const allSeriesKeys = useMemo(() => {
    61→		if (data.length === 0) return [];
    62→		const keys = new Set<string>();
    63→		for (const item of data) {
    64→			for (const key of Object.keys(item)) {
    65→				if (key !== "date") keys.add(key);
    66→			}
    67→		}
    68→		return Array.from(keys).sort();
    69→	}, [data]);
    70→
    71→	// Cap at MAX_SERIES, rest → "Other"
    72→	const { seriesKeys, hasOther } = useMemo(() => {
    73→		if (allSeriesKeys.length <= MAX_SERIES) {
    74→			return { seriesKeys: allSeriesKeys, hasOther: false };
    75→		}
    76→		// Rank by total value across all dates
    77→		const totals = new Map<string, number>();
    78→		for (const item of data) {
    79→			for (const key of allSeriesKeys) {
    80→				totals.set(key, (totals.get(key) ?? 0) + ((item[key] as number) || 0));
    81→			}
    82→		}
    83→		const sorted = Array.from(totals.entries()).sort((a, b) => b[1] - a[1]);
    84→		return {
    85→			seriesKeys: sorted.slice(0, MAX_SERIES).map(([k]) => k),
    86→			hasOther: true,
    87→		};
    88→	}, [allSeriesKeys, data]);
    89→
    90→	const filledData = useMemo(() => {
    91→		if (data.length === 0) return [];
    92→
    93→		const existingDates = Array.from(
    94→			new Set(data.map((d) => d.date as string)),
    95→		).sort();
    96→		const minDate = new Date(existingDates[0]);
    97→		const maxDate = new Date(existingDates[existingDates.length - 1]);
    98→		const dateRange: string[] = [];
    99→		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
   100→			dateRange.push(d.toISOString().split("T")[0]);
   101→		}
   102→
   103→		const dataByDate = new Map(data.map((item) => [item.date as string, item]));
   104→		const topKeysSet = new Set(seriesKeys);
   105→
   106→		return dateRange.map((dateKey) => {
   107→			const item = dataByDate.get(dateKey);
   108→			const entry: Record<string, string | number> = { date: dateKey };
   109→			for (const key of seriesKeys) {
   110→				entry[key] = item ? (item[key] as number) || 0 : 0;
   111→			}
   112→			if (hasOther) {
   113→				entry.Other = item
   114→					? allSeriesKeys
   115→							.filter((k) => !topKeysSet.has(k))
   116→							.reduce((sum, k) => sum + ((item[k] as number) || 0), 0)
   117→					: 0;
   118→			}
   119→			return entry;
   120→		});
   121→	}, [data, seriesKeys, allSeriesKeys, hasOther]);
   122→
   123→	const displayKeys = hasOther ? [...seriesKeys, "Other"] : seriesKeys;
   124→
   125→	const chartData = useMemo(() => {
   126→		if (!isCumulative) {
   127→			return filledData.map((item) => ({
   128→				...item,
   129→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
   130→					month: "short",
   131→					day: "numeric",
   132→				}),
   133→			}));
   134→		}
   135→
   136→		const cumulativeData = [];
   137→		const runningTotals: Record<string, number> = {};
   138→		for (const key of displayKeys) {
   139→			runningTotals[key] = 0;
   140→		}
   141→
   142→		for (const item of filledData) {
   143→			const cumulativeItem: Record<string, unknown> = {
   144→				date: item.date,
   145→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
   146→					month: "short",
   147→					day: "numeric",
   148→				}),
   149→			};
   150→			for (const key of displayKeys) {
   151→				runningTotals[key] += (item[key] as number) || 0;
   152→				cumulativeItem[key] = runningTotals[key];
   153→			}
   154→			cumulativeData.push(cumulativeItem);
   155→		}
   156→
   157→		return cumulativeData;
   158→	}, [filledData, isCumulative, displayKeys]);
   159→
   160→	const getDisplayName = (key: string): string => {
   161→		if (key === "Other") return "Other";
   162→		if (splitBy === "user_id" && userMap) {
   163→			return userMap[key] || `${key.substring(0, 12)}...`;
   164→		}
   165→		return key;
   166→	};
   167→
   168→	return (
   169→		<div className="space-y-4">
   170→			<div className="flex flex-wrap items-center justify-end gap-4">
   171→				<div className="flex items-center gap-2">
   172→					<Select
   173→						value={splitBy}
   174→						onValueChange={(v) =>
   175→							onSplitByChange(v as "user_id" | "repository")
   176→						}
   177→					>
   178→						<SelectTrigger className="w-40">
   179→							<SelectValue />
   180→						</SelectTrigger>
   181→						<SelectContent>
   182→							<SelectItem value="user_id">by Developer</SelectItem>
   183→							<SelectItem value="repository">by Repository</SelectItem>
   184→						</SelectContent>
   185→					</Select>
   186→				</div>
   187→
   188→				<div className="flex items-center gap-2">
   189→					<label
   190→						htmlFor="cumulative-toggle"
   191→						className="text-sm font-medium text-muted cursor-pointer"
   192→					>
   193→						Cumulative
   194→					</label>
   195→					<Switch
   196→						id="cumulative-toggle"
   197→						checked={isCumulative}
   198→						onCheckedChange={setIsCumulative}
   199→					/>
   200→				</div>
   201→			</div>
   202→
   203→			<ResponsiveContainer width="100%" height={400}>
   204→				<BarChart
   205→					data={chartData}
   206→					margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   207→				>
   208→					<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   209→					<XAxis
   210→						dataKey="displayDate"
   211→						tick={{ fontSize: 12 }}
   212→						angle={-45}
   213→						textAnchor="end"
   214→						height={80}
   215→						tickMargin={8}
   216→					/>
   217→					<YAxis tick={{ fontSize: 12 }} />
   218→					<Tooltip
   219→						contentStyle={{
   220→							backgroundColor: tooltipBg,
   221→							border: `1px solid ${tooltipBorder}`,
   222→							borderRadius: "8px",
   223→							padding: "12px",
   224→						}}
   225→						formatter={(value, name) => {
   226→							const displayName = name ? getDisplayName(String(name)) : "";
   227→							return [((value as number) ?? 0).toLocaleString(), displayName];
   228→						}}
   229→						labelFormatter={(label) => `Date: ${label}`}
   230→					/>
   231→					<Legend
   232→						formatter={(value) => getDisplayName(value)}
   233→						wrapperStyle={{ fontSize: "12px" }}
   234→					/>
   235→					{displayKeys.map((key, index) => (
   236→						<Bar
   237→							key={key}
   238→							dataKey={key}
   239→							name={key}
   240→							stackId="1"
   241→							fill={
   242→								key === "Other" ? OTHER_COLOR : COLORS[index % COLORS.length]
   243→							}
   244→						/>
   245→					))}
   246→				</BarChart>
   247→			</ResponsiveContainer>
   248→
   249→			{displayKeys.length === 0 && (
   250→				<div className="text-center text-sm text-muted py-4">
   251→					No data available for the selected time period
   252→				</div>
   253→			)}
   254→		</div>
   255→	);
   256→}
