							stroke={axisStroke}
							style={{ fontSize: "12px" }}
							angle={-45}
							textAnchor="end"
							height={80}
							tickMargin={8}
						/>
						<YAxis
							stroke={axisStroke}
							style={{ fontSize: "12px" }}
							tickFormatter={currentMetric.formatter}
						/>
						<Tooltip
							contentStyle={{
								backgroundColor: tooltipBg,
								border: `1px solid ${tooltipBorder}`,
								borderRadius: "8px",
								padding: "12px",
							}}
							formatter={(value, name) => {
								if (!name || name === "date" || name === "displayDate")
									return null;
								return [
									currentMetric.formatter((value as number) ?? 0),
									formatUsername(String(name)),
								];
							}}
							labelFormatter={(label) => label}
						/>
						<Legend
							layout="vertical"
							align="right"
							verticalAlign="top"
							width={160}
							content={({ payload }) => (
								<ChartLegend payload={payload} formatter={formatUsername} hiddenSeries={hiddenSeries} onToggle={toggleSeries} />
							)}
						/>
						{seriesList.map((userId, index) => (
							<Bar
								key={userId}
								dataKey={userId}
								stackId="1"
								fill={
									userId === "Other"
										? OTHER_COLOR
										: DEVELOPER_COLORS[index % DEVELOPER_COLORS.length]
								}
							/>
						))}
					</BarChart>
				)}
			</ResponsiveContainer>
