    84→			return next;
    85→		});
    86→
    87→	const currentMetric = METRICS[selectedMetric];
    88→
    89→	// Rank projects by total sessions (stable ordering across metric changes)
    90→	const { topProjects, topProjectsSet, hasOther } = useMemo(() => {
    91→		const projectTotals = new Map<string, number>();
    92→		for (const d of data) {
    93→			projectTotals.set(
    94→				d.project_path,
    95→				(projectTotals.get(d.project_path) ?? 0) + d.sessions,
    96→			);
    97→		}
    98→		const sorted = Array.from(projectTotals.entries()).sort(
    99→			(a, b) => b[1] - a[1],
   100→		);
   101→		const top = sorted.slice(0, MAX_SERIES).map(([p]) => p);
   102→		return {
   103→			topProjects: top,
   104→			topProjectsSet: new Set(top),
   105→			hasOther: sorted.length > MAX_SERIES,
   106→		};
   107→	}, [data]);
   108→
   109→	const { chartData, seriesList } = useMemo(() => {
   110→		// Build full date range from all data
   111→		const existingDates = Array.from(new Set(data.map((d) => d.date))).sort();
   112→		const allDates: string[] = [];
   113→		if (existingDates.length > 0) {
   114→			const minDate = new Date(existingDates[0]);
   115→			const maxDate = new Date(existingDates[existingDates.length - 1]);
   116→			for (
   117→				let d = new Date(minDate);
   118→				d <= maxDate;
   119→				d.setDate(d.getDate() + 1)
   120→			) {
   121→				allDates.push(d.toISOString().split("T")[0]);
   122→			}
   123→		}
   124→
   125→		// "Other" only applies to summable metrics, not averages
   126→		const showOther = hasOther && selectedMetric !== "success_rate";
   127→		const seriesList = showOther ? [...topProjects, "Other"] : topProjects;
   128→
   129→		const chartData = allDates.map((date) => {
   130→			const dateObj: Record<string, string | number> = {
   131→				date,
   132→				displayDate: new Date(date).toLocaleDateString("en-US", {
   133→					month: "short",
   134→					day: "numeric",
   135→				}),
   136→			};
   137→
   138→			for (const projectPath of topProjects) {
   139→				const dp = data.find(
   140→					(d) => d.date === date && d.project_path === projectPath,
   141→				);
   142→				dateObj[projectPath] = dp
   143→					? (dp[currentMetric.key as keyof ProjectTrendDataPoint] as number)
   144→					: 0;
   145→			}
   146→
   147→			if (showOther) {
   148→				dateObj.Other = data
   149→					.filter((d) => d.date === date && !topProjectsSet.has(d.project_path))
   150→					.reduce(
   151→						(sum, d) =>
   152→							sum +
   153→							((d[
   154→								currentMetric.key as keyof ProjectTrendDataPoint
   155→							] as number) ?? 0),
   156→						0,
   157→					);
   158→			}
   159→
   160→			return dateObj;
   161→		});
   162→
   163→		return { chartData, seriesList };
   164→	}, [
   165→		data,
   166→		topProjects,
   167→		topProjectsSet,
   168→		hasOther,
   169→		selectedMetric,
   170→		currentMetric,
   171→	]);
   172→
   173→	const formatProjectName = (projectPath: string) => {
   174→		if (projectPath === "Other") return "Other";
   175→		const parts = projectPath.split("/");
   176→		return parts[parts.length - 1] || projectPath.substring(0, 20);
   177→	};
   178→
   179→	return (
   180→		<div className="space-y-4">
   181→			<div className="flex flex-wrap gap-2">
   182→				{Object.entries(METRICS).map(([key, metric]) => {
