   186→						<button
   187→							type="button"
   188→							key={key}
   189→							onClick={() => setSelectedMetric(key as MetricType)}
   190→							className={`
   191→								flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium
   192→								transition-all duration-200
   193→								${
   194→									isSelected
   195→										? "bg-accent-light text-accent-text border-2 border-accent"
   196→										: "bg-surface text-muted border-2 border-transparent hover:bg-hover"
   197→								}
   198→							`}
   199→						>
   200→							<Icon className="w-4 h-4" />
   201→							<span>{metric.label}</span>
   202→						</button>
   203→					);
   204→				})}
   205→			</div>
   206→
   207→			<ResponsiveContainer width="100%" height={400}>
   208→				{selectedMetric === "success_rate" ? (
   209→					<LineChart
   210→						data={chartData}
   211→						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
   212→					>
   213→						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
   214→						<XAxis
   215→							dataKey="displayDate"
   216→							stroke={axisStroke}
   217→							style={{ fontSize: "12px" }}
   218→							angle={-45}
   219→							textAnchor="end"
   220→							height={80}
   221→							tickMargin={8}
   222→						/>
   223→						<YAxis
   224→							stroke={axisStroke}
