   226→							tickFormatter={currentMetric.formatter}
   227→							domain={[0, 100]}
   228→						/>
   229→						<Tooltip
   230→							contentStyle={{
   231→								backgroundColor: tooltipBg,
   232→								border: `1px solid ${tooltipBorder}`,
