						/>
						{topProjects.map((projectPath, index) => (
							<Line
								key={projectPath}
								type="monotone"
								dataKey={projectPath}
								stroke={PROJECT_COLORS[index % PROJECT_COLORS.length]}
								strokeWidth={2}
								dot={{ r: 3 }}
								activeDot={{ r: 5 }}
								connectNulls
								hide={hiddenSeries.has(projectPath)}
							/>
						))}
					</LineChart>
				) : (
					<BarChart
						data={chartData}
						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
					>
						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
						<XAxis
							dataKey="displayDate"
							stroke={axisStroke}
							style={{ fontSize: "12px" }}
							angle={-45}
							textAnchor="end"
							height={80}
							tickMargin={8}
						/>
						<YAxis
							stroke={axisStroke}
							style={{ fontSize: "12px" }}
							tickFormatter={currentMetric.formatter}
						/>
						<Tooltip
							contentStyle={{
								backgroundColor: tooltipBg,
								border: `1px solid ${tooltipBorder}`,
								borderRadius: "8px",
								padding: "12px",
							}}
							formatter={(value, name) => {
								if (!name || name === "date" || name === "displayDate")
									return null;
								return [
									currentMetric.formatter((value as number) ?? 0),
									formatProjectName(String(name)),
								];
							}}
							labelFormatter={(label) => label}
						/>
						<Legend
							layout="vertical"
							align="right"
							verticalAlign="top"
							width={160}
							content={({ payload }) => (
								<ChartLegend
									payload={payload}
									formatter={formatProjectName}
									hiddenSeries={hiddenSeries}
									onToggle={toggleSeries}
								/>
							)}
						/>
						{seriesList.map((projectPath, index) => (
							<Bar
								key={projectPath}
								dataKey={projectPath}
								stackId="1"
								hide={hiddenSeries.has(projectPath)}
								fill={
									projectPath === "Other"
										? OTHER_COLOR
										: PROJECT_COLORS[index % PROJECT_COLORS.length]
								}
							/>
						))}
					</BarChart>
				)}
			</ResponsiveContainer>
		</div>
	);
}

