import type { ErrorTrendDataPoint } from "@rudel/api-routes";
import { useMemo, useState } from "react";
import {
	Bar,
	BarChart,
	CartesianGrid,
	Legend,
	Line,
	LineChart,
	ResponsiveContainer,
	Tooltip,
	XAxis,
	YAxis,
} from "recharts";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { useChartTheme } from "@/hooks/useChartTheme";
import { ChartLegend } from "./ChartLegend";

const MAX_SERIES = 14;
const OTHER_COLOR = "#9ca3af";

interface ErrorTrendChartProps {
	data: ErrorTrendDataPoint[];
	metric:
		| "avg_errors_per_interaction"
		| "avg_errors_per_session"
		| "total_errors";
	splitBy: "repository" | "user_id" | "model";
	onMetricChange: (
		metric:
			| "avg_errors_per_interaction"
			| "avg_errors_per_session"
			| "total_errors",
	) => void;
	onSplitByChange: (splitBy: "repository" | "user_id" | "model") => void;
	userMap?: Record<string, string>;
}

const COLORS = [
	"#ef4444",
	"#f59e0b",
	"#10b981",
	"#3b82f6",
	"#8b5cf6",
	"#ec4899",
	"#06b6d4",
	"#14b8a6",
	"#f97316",
	"#6366f1",
	"#84cc16",
	"#a855f7",
	"#f43f5e",
	"#0ea5e9",
];

const METRIC_LABELS: Record<string, string> = {
	avg_errors_per_interaction: "Avg Errors per Interaction",
	avg_errors_per_session: "Avg Errors per Session",
	total_errors: "Total Errors",
};

const SPLIT_LABELS: Record<string, string> = {
	repository: "by Repository",
	user_id: "by Developer",
	model: "by Model",
};

export function ErrorTrendChart({
	data,
	metric,
	splitBy,
	onMetricChange,
	onSplitByChange,
	userMap,
}: ErrorTrendChartProps) {
	const { tooltipBg, tooltipBorder, gridStroke } = useChartTheme();
	const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());
	const toggleSeries = (key: string) =>
		setHiddenSeries((prev) => {
			const next = new Set(prev);
			next.has(key) ? next.delete(key) : next.add(key);
			return next;
		});

	const { seriesKeys, chartData } = useMemo(() => {
		if (data.length === 0) return { seriesKeys: [], chartData: [] };

		// Compute totals per dimension to rank and cap at MAX_SERIES
		const dimTotals = new Map<string, number>();
		for (const item of data) {
			dimTotals.set(
				item.dimension,
				(dimTotals.get(item.dimension) ?? 0) + ((item[metric] as number) ?? 0),
			);
		}

		const sortedDims = Array.from(dimTotals.entries()).sort(
			(a, b) => b[1] - a[1],
		);
		const topDims = sortedDims.slice(0, MAX_SERIES).map(([k]) => k);
		const topDimsSet = new Set(topDims);
		// Only add "Other" for total_errors (summable); avg metrics are not meaningful to sum
		const hasOther =
			metric === "total_errors" && sortedDims.length > MAX_SERIES;
		const seriesKeys = hasOther ? [...topDims, "Other"] : topDims;

		// Build full date range
		const allDates = Array.from(new Set(data.map((item) => item.date))).sort();
		const minDate = new Date(allDates[0]);
		const maxDate = new Date(allDates[allDates.length - 1]);
		const dateRange: string[] = [];
		for (let d = new Date(minDate); d <= maxDate; d.setDate(d.getDate() + 1)) {
			dateRange.push(d.toISOString().split("T")[0]);
		}

		const dateMap = new Map<string, Record<string, unknown>>();
		for (const dateKey of dateRange) {
			const dateData: Record<string, unknown> = {
				date: dateKey,
				displayDate: new Date(dateKey).toLocaleDateString("en-US", {
					month: "short",
					day: "numeric",
				}),
			};
			for (const key of seriesKeys) {
				dateData[key] = 0;
			}
			dateMap.set(dateKey, dateData);
		}

		for (const item of data) {
			const dateData = dateMap.get(item.date);
			if (!dateData) continue;
			if (topDimsSet.has(item.dimension)) {
				dateData[item.dimension] = item[metric];
			} else if (hasOther) {
				dateData.Other =
					((dateData.Other as number) ?? 0) + ((item[metric] as number) ?? 0);
			}
		}

		return {
			seriesKeys,
			chartData: Array.from(dateMap.values()).sort((a, b) =>
				(a.date as string).localeCompare(b.date as string),
			),
		};
	}, [data, metric]);

	const getDisplayName = (key: string): string => {
		if (key === "Other") return "Other";
		if (splitBy === "user_id" && userMap) {
			return userMap[key] || `${key.substring(0, 12)}...`;
		}
		return key;
	};

	return (
		<div className="space-y-4">
			<div className="flex flex-wrap items-center justify-between gap-4">
				<div className="flex items-center gap-2">
					<label
						htmlFor="error-metric-select"
						className="text-sm font-medium text-muted"
					>
						Metric:
					</label>
					<Select
						value={metric}
						onValueChange={(v) => onMetricChange(v as typeof metric)}
					>
						<SelectTrigger className="w-56">
							<SelectValue />
						</SelectTrigger>
						<SelectContent>
							{Object.entries(METRIC_LABELS).map(([key, label]) => (
								<SelectItem key={key} value={key}>
									{label}
								</SelectItem>
							))}
						</SelectContent>
					</Select>
				</div>

				<div className="flex items-center gap-2">
					<label
						htmlFor="error-split-select"
						className="text-sm font-medium text-muted"
					>
						Split:
					</label>
					<Select
						value={splitBy}
						onValueChange={(v) => onSplitByChange(v as typeof splitBy)}
					>
						<SelectTrigger className="w-40">
							<SelectValue />
						</SelectTrigger>
						<SelectContent>
							{Object.entries(SPLIT_LABELS).map(([key, label]) => (
								<SelectItem key={key} value={key}>
									{label}
								</SelectItem>
							))}
						</SelectContent>
					</Select>
				</div>
			</div>

			<ResponsiveContainer width="100%" height={400}>
				{metric === "total_errors" ? (
					<BarChart
						data={chartData}
						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
					>
						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
						<XAxis
							dataKey="displayDate"
							tick={{ fontSize: 12 }}
							angle={-45}
							textAnchor="end"
							height={80}
							tickMargin={8}
						/>
						<YAxis tick={{ fontSize: 12 }} />
						<Tooltip
							contentStyle={{
								backgroundColor: tooltipBg,
								border: `1px solid ${tooltipBorder}`,
								borderRadius: "8px",
								padding: "12px",
							}}
							formatter={(value, name) => {
								const displayName = name ? getDisplayName(String(name)) : "";
								return [((value as number) ?? 0).toLocaleString(), displayName];
							}}
							labelFormatter={(label) => `Date: ${label}`}
						/>
						<Legend
							layout="vertical"
							align="right"
							verticalAlign="top"
							width={160}
							content={({ payload }) => (
								<ChartLegend
									payload={payload}
									formatter={getDisplayName}
									hiddenSeries={hiddenSeries}
									onToggle={toggleSeries}
								/>
							)}
						/>
						{seriesKeys.map((key, index) => (
							<Bar
								key={key}
								dataKey={key}
								name={key}
								stackId="1"
								hide={hiddenSeries.has(key)}
								fill={
									key === "Other" ? OTHER_COLOR : COLORS[index % COLORS.length]
								}
							/>
						))}
					</BarChart>
				) : (
					<LineChart
						data={chartData}
						margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
					>
						<CartesianGrid strokeDasharray="3 3" stroke={gridStroke} />
						<XAxis
							dataKey="displayDate"
							tick={{ fontSize: 12 }}
							angle={-45}
							textAnchor="end"
							height={80}
							tickMargin={8}
						/>
						<YAxis tick={{ fontSize: 12 }} />
						<Tooltip
							contentStyle={{
								backgroundColor: tooltipBg,
								border: `1px solid ${tooltipBorder}`,
								borderRadius: "8px",
								padding: "12px",
							}}
							formatter={(value, name) => {
								const displayName = name ? getDisplayName(String(name)) : "";
								return [((value as number) ?? 0).toFixed(2), displayName];
							}}
							labelFormatter={(label) => `Date: ${label}`}
						/>
						<Legend
							layout="vertical"
							align="right"
							verticalAlign="top"
							width={160}
							content={({ payload }) => (
								<ChartLegend
									payload={payload}
									formatter={getDisplayName}
									hiddenSeries={hiddenSeries}
									onToggle={toggleSeries}
								/>
							)}
						/>
						{seriesKeys.map((key, index) => (
							<Line
								key={key}
								type="monotone"
								dataKey={key}
								name={key}
								stroke={COLORS[index % COLORS.length]}
								strokeWidth={2}
								dot={{ r: 4 }}
								activeDot={{ r: 6 }}
								connectNulls={false}
								hide={hiddenSeries.has(key)}
							/>
						))}
					</LineChart>
				)}
			</ResponsiveContainer>

			{seriesKeys.length === 0 && (
				<div className="text-center text-sm text-muted py-4">
					No error data available for the selected time period
				</div>
			)}
		</div>
	);
}

import { AlertCircle, AlertTriangle, Clock, Users } from "lucide-react";
import { useState } from "react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ErrorTrendChart } from "@/components/charts/ErrorTrendChart";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { useUserMap } from "@/hooks/useUserMap";
import { orpc } from "@/lib/orpc";

const severityColors = {
	high: "bg-status-error-bg text-status-error-text border-status-error-border",
	medium:
		"bg-status-warning-bg text-status-warning-text border-status-warning-border",
	low: "bg-status-info-bg text-status-info-text border-status-info-border",
};

const severityIcons = {
	high: "\u{1F534}",
	medium: "\u{1F7E1}",
	low: "\u{1F535}",
};

export function ErrorsPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [trendMetric, setTrendMetric] = useState<
		"avg_errors_per_interaction" | "avg_errors_per_session" | "total_errors"
	>("total_errors");
	const [trendSplitBy, setTrendSplitBy] = useState<
		"repository" | "user_id" | "model"
	>("repository");

	const { data: errors, isLoading } = useAnalyticsQuery(
		orpc.analytics.errors.topRecurring.queryOptions({
			input: { days, minOccurrences: 2, limit: 15 },
		}),
	);

	const { data: trendData, isLoading: trendLoading } = useAnalyticsQuery(
		orpc.analytics.errors.trends.queryOptions({
			input: { startDate, endDate, splitBy: trendSplitBy },
		}),
	);

	const { userMap } = useUserMap();

	const totalErrors = errors?.reduce((sum, e) => sum + e.occurrences, 0) ?? 0;
	const highSeverityCount =
		errors?.filter((e) => e.severity === "high").length ?? 0;
	const affectedUsersTotal =
		errors && errors.length > 0
			? Math.max(...errors.map((e) => e.affected_users))
			: 0;
	const mostCommonError =
		errors && errors.length > 0 ? errors[0].error_pattern : "None";

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Error Intelligence"
					description="Track and analyze recurring errors across your team"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading error data...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Error Intelligence"
				description="Track and analyze recurring errors across your team"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Errors"
					value={totalErrors.toLocaleString()}
					subtitle="error occurrences"
					icon={AlertCircle}
					iconColor="text-red-600"
				/>
				<StatCard
					title="High Severity"
					value={highSeverityCount}
					subtitle="critical issues"
					icon={AlertTriangle}
					iconColor="text-orange-600"
				/>
				<StatCard
					title="Most Common"
					value={mostCommonError}
					subtitle="top error type"
					icon={Clock}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Max Affected Users"
					value={affectedUsersTotal}
					subtitle="developers impacted"
					icon={Users}
					iconColor="text-blue-600"
				/>
			</div>

			{/* Error Trends Chart */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-2">
					Error Trends Over Time
				</h2>
				<p className="text-sm text-muted mb-6">
					Track error metrics across different dimensions to identify patterns
					and trends
				</p>
				{trendLoading ? (
					<div className="text-center py-12 text-muted">
						Loading error trends...
					</div>
				) : (
					<ErrorTrendChart
						data={trendData || []}
						metric={trendMetric}
						splitBy={trendSplitBy}
						onMetricChange={setTrendMetric}
						onSplitByChange={setTrendSplitBy}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Top Recurring Errors */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-4">
					Top Recurring Errors
				</h2>
				<p className="text-sm text-muted mb-6">
					Most frequently occurring errors that may need attention
				</p>
				{errors && errors.length > 0 ? (
					<div className="space-y-4">
						{errors.map((err, index) => (
							<div
								// biome-ignore lint/suspicious/noArrayIndexKey: static list of errors
								key={index}
								className="border border-border rounded-lg p-4 hover:shadow-md transition-shadow"
							>
								<div className="flex items-start justify-between">
									<div className="flex-1">
										<div className="flex items-center gap-3 mb-2">
											<span className="text-2xl">
												{
													severityIcons[
														err.severity as keyof typeof severityIcons
													]
												}
											</span>
											<h3 className="text-lg font-semibold text-heading">
												{err.error_pattern}
											</h3>
											<span
												className={`px-3 py-1 rounded-full text-xs font-medium border ${
													severityColors[
														err.severity as keyof typeof severityColors
													]
												}`}
											>
												{err.severity.toUpperCase()}
											</span>
										</div>
										<div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-3">
											<div>
												<p className="text-xs text-muted uppercase">
													Occurrences
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.occurrences}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Affected Users
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.affected_users}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Last Seen
												</p>
												<p className="text-sm text-subheading">
													{new Date(err.last_seen).toLocaleDateString()}
												</p>
											</div>
										</div>
									</div>
								</div>
							</div>
						))}
					</div>
				) : (
					<div className="text-center py-12">
						<div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-status-success-bg mb-4">
							<svg
								className="w-8 h-8 text-status-success-icon"
								fill="none"
								stroke="currentColor"
								viewBox="0 0 24 24"
								role="img"
								aria-label="No errors"
							>
								<path
									strokeLinecap="round"
									strokeLinejoin="round"
									strokeWidth={2}
									d="M5 13l4 4L19 7"
								/>
							</svg>
						</div>
						<p className="text-lg font-medium text-foreground mb-1">
							No recurring errors found!
						</p>
						<p className="text-sm text-muted">
							Great job! Your team hasn't encountered any recurring errors in
							the selected time period.
						</p>
					</div>
				)}
			</AnalyticsCard>

			{/* Error Insights */}
			{errors && errors.length > 0 && (
				<div className="grid grid-cols-1 md:grid-cols-2 gap-6">
					<AnalyticsCard className="bg-status-error-bg border-status-error-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-error-bg">
								<AlertTriangle className="h-6 w-6 text-status-error-icon" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Action Recommended
								</h3>
								<p className="text-sm text-subheading mb-3">
									You have {highSeverityCount} high-severity error
									{highSeverityCount !== 1 ? "s" : ""} that may require
									immediate attention.
								</p>
								{highSeverityCount > 0 && (
									<p className="text-xs text-muted">
										Consider scheduling a team discussion to address these
										issues.
									</p>
								)}
							</div>
						</div>
					</AnalyticsCard>

					<AnalyticsCard className="bg-status-info-bg border-status-info-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-info-bg">
								<Users className="h-6 w-6 text-accent" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Knowledge Sharing
								</h3>
								<p className="text-sm text-subheading mb-3">
									{errors.filter((e) => e.affected_users > 1).length} error type
									{errors.filter((e) => e.affected_users > 1).length !== 1
										? "s"
										: ""}{" "}
									affecting multiple developers.
								</p>
								<p className="text-xs text-muted">
									Share solutions in team channels to help everyone learn.
								</p>
							</div>
						</div>
					</AnalyticsCard>
				</div>
			)}
		</div>
	);
}

