								dot={{ r: 4 }}
								activeDot={{ r: 6 }}
								connectNulls={false}
								hide={hiddenSeries.has(key)}
							/>
						))}
					</LineChart>
				)}
			</ResponsiveContainer>

			{seriesKeys.length === 0 && (
				<div className="text-center text-sm text-muted py-4">
					No error data available for the selected time period
				</div>
			)}
		</div>
	);
}

